var _ ILauncherApps = (*launcherAppsStubWrapper)(nil)

// NewLauncherAppsStub creates a server-side ILauncherApps wrapping the given
// server implementation. The returned value satisfies ILauncherApps
// and can be passed to proxy methods; its AsBinder() returns a
// *binder.StubBinder that is auto-registered with the binder
// driver on first use.
func NewLauncherAppsStub(
	impl ILauncherAppsServer,
) ILauncherApps {
	wrapper := &launcherAppsStubWrapper{impl: impl}
	stub := &LauncherAppsStub{Impl: wrapper}
	wrapper.stubBinder = binder.NewStubBinder(stub)
	return wrapper
}
